"use client";

import Link from "next/link";
import Image from "next/image";
import { useState, useEffect, useCallback } from "react";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { faTrash } from "@fortawesome/free-solid-svg-icons";
import styles from "./styles.module.scss";

interface CartItem {
  id: number;
  name: string;
  image: string;
  price: number;
  quantity: number;
}

export default function CartPage() {
  const [cartItems, setCartItems] = useState<CartItem[]>([
    {
      id: 1,
      name: "IPHONE 16 PRO MAX",
      image: "/iphone.png",
      price: 120000,
      quantity: 2,
    },
    {
      id: 2,
      name: "IPHONE 1 PRO MAX",
      image: "/iphone1.png",
      price: 250000,
      quantity: 1,
    },
  ]);

  const [totalPrice, setTotalPrice] = useState(0);

  // Use useCallback for memoizing the handlers
  const handleQuantityChange = useCallback(
    (itemId: number, newQuantity: number) => {
      setCartItems((prevItems) =>
        prevItems.map((item) =>
          item.id === itemId
            ? { ...item, quantity: Math.max(1, newQuantity) }
            : item
        )
      );
    },
    [] // Empty dependency array means this function is only created once
  );

  const handleRemoveItem = useCallback((itemId: number) => {
    setCartItems((prevItems) => prevItems.filter((item) => item.id !== itemId));
  }, []);

  // Moved total price calculation into useCallback as well.  It's efficient even without it, but good practice.
  const calculateTotalPrice = useCallback((items: CartItem[]) => {
    return items.reduce((total, item) => total + item.price * item.quantity, 0);
  }, []);

  useEffect(() => {
    setTotalPrice(calculateTotalPrice(cartItems));
  }, [cartItems, calculateTotalPrice]); // Recalculate when cartItems or calculateTotalPrice change

  return (
    <div className={styles.cartContainer}>
      <h1 className={styles.cartTitle}>Giỏ hàng của bạn</h1>{" "}
      {/* Apply the class */}
      {cartItems.length === 0 ? (
        <div className={styles.emptyCart}>
          <p>Giỏ hàng của bạn đang trống.</p>
          <Link href="/">Tiếp tục mua sắm</Link>
        </div>
      ) : (
        <div className={styles.cartItems}>
          {cartItems.map((item) => (
            <div key={item.id} className={styles.cartItem}>
              <Image
                src={item.image}
                alt={item.name}
                width={80}
                height={80}
                className={styles.itemImage}
                onError={(e) => {
                  console.error("Image failed to load", item.image);
                  // Optionally, set a fallback image URL
                  // (e.target as HTMLImageElement).src = '/fallback-image.png';
                }}
              />
              <div className={styles.itemInfo}>
                <p className={styles.itemName}>{item.name}</p>
                <p className={styles.itemPrice}>
                  {item.price.toLocaleString()} VNĐ
                </p>
              </div>
              <div className={styles.quantityControls}>
                <button
                  onClick={() =>
                    handleQuantityChange(item.id, item.quantity - 1)
                  }
                  disabled={item.quantity <= 1}
                >
                  -
                </button>
                <span>{item.quantity}</span>
                <button
                  onClick={() =>
                    handleQuantityChange(item.id, item.quantity + 1)
                  }
                >
                  +
                </button>
              </div>
              <p className={styles.itemTotal}>
                {(item.price * item.quantity).toLocaleString()} VNĐ
              </p>
              <FontAwesomeIcon
                icon={faTrash}
                onClick={() => handleRemoveItem(item.id)}
                className={styles.deleteIcon}
              />
            </div>
          ))}
        </div>
      )}
      <div className={styles.cartFooter}>
        <strong>Tổng cộng: {totalPrice.toLocaleString()} VNĐ</strong>
        <button
          className={styles.checkoutButton}
          disabled={cartItems.length === 0}
        >
          Thanh toán
        </button>
      </div>
    </div>
  );
}
